"use strict";function initGrid(){document.querySelectorAll(".grid-container").forEach(function(e){var t=new Masonry(e,{itemSelector:".grid-item"});e.classList.contains("grid-item-hide")&&(window.aboutMasonry=t),imagesLoaded(e,function(){e.style.opacity=1,t.layout()}),e.querySelectorAll(".toggle-show").forEach(function(e){e.addEventListener("change",function(){setTimeout(function(){t.layout()},360)})})})}document.addEventListener("DOMContentLoaded",function(){initGrid()}),typeof Turbo!="undefined"&&document.addEventListener("turbo:load",initGrid)